const raw = $json["text"] || "";

// remove markdown
let cleaned = raw
  .replace(/```html/g, "")
  .replace(/```/g, "")
  .trim();

// extract html only
const match = cleaned.match(/<!DOCTYPE html>[\s\S]*/);

return [
  {
    json: {
      html: match ? match[0] : cleaned
    }
  }
];

